function evidence_httpsts_semantics_retry_proof_vd4aey(method: string, exists: boolean, validatorMatches: boolean): { status: number; mutates: boolean } {
  const normalized = method.toUpperCase();
  if (normalized === "GET") return { status: exists ? 200 : 404, mutates: false };
